text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "민준",
      "서연",
      "도윤",
      "하라"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다.",
        "conditions": [
          "스모크 테스트가 먼저 통과해야 한다."
        ]
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다. 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경하자.",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표일 뿐이며 확정 공개 일정이 아니다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자는 지정되지 않았다."
      },
      {
        "topic": "하라의 tarball 경로 점검",
        "note": "민준의 스모크 결과 공유 후 확인하기로 했으나 정확한 시한은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태이면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "민준",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "도윤",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "중간"
    },
    {
      "owner": "하라",
      "task": "민준이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정",
      "source_certainty": "높음"
    }
  ],
  "followup_note": {
    "check_next": [
      "민준의 스모크 테스트 결과 통과 여부를 확인한다.",
      "도윤의 실패 트리아지 노트 작성 완료 여부를 확인한다.",
      "스모크 결과 공유 이후 하라의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 답을 확보한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자",
      "명시되지 않은 추가 마감일"
    ]
  },
  "non_invention_rules": [
    "고객명, 외부 파트너, 예산, 보안, 장애, 법무 관련 사실은 언급된 범위 밖으로 확장하지 않는다.",
    "담당자가 명시되지 않은 항목은 owner를 null 또는 미배정으로 유지한다.",
    "정확한 시한이 없는 항목은 임의 시각이나 날짜를 추가하지 않는다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "반려된 제안과 확정된 결정은 섞지 않고 분리한다.",
    "공개 릴리스 목표는 스모크 테스트 통과 조건이 붙은 금요일 15:00 KST로만 기록한다."
  ]
}
